    openSource(a) {
        this.openApp("../../viewer/viewer", "Declare Viewer", null, "program=" + this.sourceRel(a))
        },

    // ── the command seam: the menu bar, the dock, and keys all route here ──

    command(id) {
        if (id == "new") {
            if (this.activeApp == "markdown") this.openViewer("../../docs/declare.md", "declare.md")
            else if (this.activeApp == "calendar") this.openApp("../../calendar/calendar", "Calendar", null, "base=../calendar/")
            else if (this.activeApp == "declareviewer") this.openApp("../../viewer/viewer", "Declare Viewer", null, "program=desktop.declare")
            else if (this.activeApp == "jots") this.newJot("", null)
            else this.newFiles()
