        else if (id == "close") { if (this.frontWin != null) this.closeWin(this.frontWin) }
        else if (id == "dark") { this.root.darkChoice = !this.root.darkMode; this.root.darkLocked = true }
        else if (id == "about-desktop") this.openAbout("desktop")
        else if (id == "about-app") this.openAbout(this.activeApp)
        else if (id == "source-desktop") this.openSource("desktop")
        else if (id == "home") this.root.navigate("apps/homepage/homepage.declare")   // distro-root-relative → works on dev server AND static host
        else if (id == "source") this.openSource(this.activeApp)
        else if (id == "quit") this.quitApp(this.activeApp)
