        for (const w of doomed) this.closeWin(w)
        if (a == "markdown") this.mdRunning = false
        else if (a == "calendar") this.calRunning = false
        else if (a == "declareviewer") this.dvRunning = false
        else if (a == "jots") this.jotRunning = false
